class Solution:
    def maxEvents(self, events):
        # brute matching: for each day, take the still-open event with the
        # earliest end among unused ones (bounded inputs keep this feasible).
        evs = sorted(events, key=lambda e: (e[0], e[1]))
        used = [False] * len(evs)
        if not evs:
            return 0
        last_day = max(e[1] for e in evs)
        attended = 0
        for day in range(1, last_day + 1):
            best = -1
            best_end = None
            for i, e in enumerate(evs):
                if not used[i] and e[0] <= day <= e[1]:
                    if best_end is None or e[1] < best_end:
                        best_end = e[1]
                        best = i
            if best != -1:
                used[best] = True
                attended += 1
        return attended

