import heapq


class Solution:
    def maxEvents(self, events):
        events.sort()
        heap = []
        i = 0
        n = len(events)
        day = 0
        attended = 0
        while i < n or heap:
            if not heap:
                day = events[i][0]
            while i < n and events[i][0] <= day:
                heapq.heappush(heap, events[i][1])
                i += 1
            while heap and heap[0] < day:
                heapq.heappop(heap)
            if heap:
                heapq.heappop(heap)
                attended += 1
                day += 1
        return attended

