var maxEvents = function(events) {
    events.sort((a, b) => a[0] - b[0]);
    const heap = [];
    const up = (i) => { while (i > 0) { const p = (i - 1) >> 1; if (heap[p] <= heap[i]) break; [heap[p], heap[i]] = [heap[i], heap[p]]; i = p; } };
    const down = (i) => { const n = heap.length; for (;;) { let l = 2 * i + 1, r = l + 1, b = i; if (l < n && heap[l] < heap[b]) b = l; if (r < n && heap[r] < heap[b]) b = r; if (b === i) break; [heap[b], heap[i]] = [heap[i], heap[b]]; i = b; } };
    const push = (v) => { heap.push(v); up(heap.length - 1); };
    const pop = () => { const top = heap[0]; const last = heap.pop(); if (heap.length) { heap[0] = last; down(0); } return top; };
    let i = 0, day = 0, attended = 0;
    const n = events.length;
    while (i < n || heap.length) {
        if (!heap.length) day = events[i][0];
        while (i < n && events[i][0] <= day) { push(events[i][1]); i++; }
        while (heap.length && heap[0] < day) pop();
        if (heap.length) { pop(); attended++; day++; }
    }
    return attended;
};
